+  MOCK_PRICE_DETAILS_DATA,
+  MOCK_PRICE_DETAILS_QUANTITIES,
+} from '@customink/pigment-extensions/reco/mocks/priceDetails';
+
+const meta: Meta<PopoverProps> = {
+  title: 'Extensions/Reco/Atoms/Popover',
+  component: Popover,
+  parameters: {
+    layout: 'centered',
+    docs: {
+      description: {
+        component:
+          'Pure CSS/React popover for rich content panels. No external positioning library. Shows on hover and keyboard focus. Use for multi-line content such as price breakdown tables — contrast with the simple label Tooltip pattern.',
+      },
+    },
+  },
+  argTypes: {
+    placement: {
+      control: 'radio',
+      options: ['top', 'bottom', 'left', 'right', 'auto'],
+      description: "Preferred placement. 'auto' picks the side with the most viewport space when the popover opens.",
+    },
+  },
+  args: {
+    placement: 'auto',
+  },
+};
+
+export default meta;
+type Story = StoryObj<PopoverProps>;
+
+const TriggerButton = ({ label }: { label: string }) => (
+  <button
+    type="button"
+    style={{
+      padding: '0.25rem 0.5rem',
+      border: 'none',
+      background: 'none',
+      cursor: 'pointer',
+      fontSize: '0.875rem',
+      fontWeight: 700,
+      color: 'var(--neutral-text-primary)',
+      textDecoration: 'underline',
+      textDecorationStyle: 'dashed',
+      textUnderlineOffset: '3px',
+    }}
+  >
+    {label}
+  </button>
+);
+
+const PRICE_DETAILS_CONTENT = (
+  <ProductCardPriceDetailsContent
+    isLoading={false}
+    isError={false}
+    priceDetailsData={MOCK_PRICE_DETAILS_DATA}
+    quotableQuantities={MOCK_PRICE_DETAILS_QUANTITIES}
+  />
+);
+
+export const Default: Story = {
+  render: (args) => (
+    <Popover {...args} content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const PlacementTop: Story = {
+  name: 'Placement: Top',
+  render: (args) => (
+    <Popover {...args} placement="top" content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const PlacementRight: Story = {
+  name: 'Placement: Right',
+  render: (args) => (
+    <Popover {...args} placement="right" content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const PlacementLeft: Story = {
+  name: 'Placement: Left',
+  render: (args) => (
+    <Popover {...args} placement="left" content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const AutoPlacement: Story = {
+  name: 'Auto Placement',
+  parameters: {
+    layout: 'fullscreen',
+    docs: {
+      description: {
+        story:
+          "placement='auto' measures available viewport space when the popover opens and picks the side with more room. Hover the top trigger — it opens downward. Hover the bottom trigger — it opens upward.",
+      },
+    },
+  },
+  render: (args) => (
+    <div
+      style={{
+        height: '100dvh',
+        display: 'flex',
+        flexDirection: 'column',
+        justifyContent: 'space-between',
+        padding: '1rem',
+      }}
+    >
+      <Popover {...args} placement="auto" content={PRICE_DETAILS_CONTENT}>
+        <TriggerButton label="Near top → opens below" />
+      </Popover>
+      <Popover {...args} placement="auto" content={PRICE_DETAILS_CONTENT}>
+        <TriggerButton label="Near bottom → opens above" />
+      </Popover>
+    </div>
+  ),
+};
+
+export const API: Story = {
+  render: (args) => (
+    <Popover {...args} content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
