+  title: 'Extensions/Reco/FavoriteButton',
+  component: FavoriteButton,
+  parameters: {
+    layout: 'centered',
+    docs: {
+      description: {
+        component:
+          'Heart toggle rendered as an absolute overlay in the top-right of a product image. The consuming app owns favorites state and passes it via `renderFavoriteButton` on ProductsCarouselWidget.',
+      },
+    },
+  },
+  // Simulate the product image context the button lives in
+  decorators: [
