+          paddingTop: '100%',
+          backgroundImage: `url(${MOCK_PRODUCTS[0].imageSrc})`,
+          backgroundSize: 'cover',
+          borderRadius: '0.5rem',
+          overflow: 'hidden',
+        }}
+      >
+        <Story />
+      </div>
+    ),
+  ],
+  argTypes: {
+    isFavorited: { control: 'boolean' },
+  },
+};
+
+export default meta;
+type Story = StoryObj<FavoriteButtonProps>;
+
+export const Default: Story = {
+  name: 'Not Favorited',
+  args: {
+    isFavorited: false,
+    // eslint-disable-next-line react/jsx-no-bind
+    onClick: () => {},
+  },
+};
+
+export const Favorited: Story = {
+  args: {
+    isFavorited: true,
+    // eslint-disable-next-line react/jsx-no-bind
+    onClick: () => {},
+  },
+};
+
+export const Interactive: Story = {
+  parameters: {
+    docs: {
+      description: {
+        story: 'Click the heart to toggle favorites state.',
+      },
+    },
+  },
+  render: () => {
+    // eslint-disable-next-line react-hooks/rules-of-hooks
+    const [isFavorited, setIsFavorited] = useState(false);
+    return (
+      // eslint-disable-next-line react/jsx-no-bind
+      <FavoriteButton isFavorited={isFavorited} onClick={() => setIsFavorited((v) => !v)} />
