    15→+/**
    16→+ * Lightweight fetch mock decorator — no MSW required.
    17→+ *
    18→+ * In any story, set `parameters.fetchMock` to a map of URL substring → response body:
    19→+ *
    20→+ * ```ts
    21→+ * parameters: {
    22→+ *   fetchMock: {
    23→+ *     '/products/quotes/new': MOCK_QUOTES_API_RESPONSE,
    24→+ *   },
    25→+ * },
    26→+ * ```
    27→+ *
    28→+ * Requests whose URL contains the key are intercepted and return the mock JSON.
    29→+ * All other requests fall through to the real `window.fetch`.
    30→+ * The original fetch is restored when the story unmounts.
    31→+ */
    32→+const FetchMockWrapper = ({ Story, handlers }: { Story: React.ComponentType; handlers: Record<string, unknown> }) => {
    33→+  // Patch synchronously during render so the mock is in place before child effects fire.
    34→+  // (React runs child useEffects before parent useEffects, so patching in useEffect is too late.)
    35→+  const originalFetchRef = React.useRef(window.fetch);
    36→+  window.fetch = async (input: RequestInfo | URL, init?: RequestInit) => {
    37→+    const url = input.toString();
    38→+    for (const [pattern, responseBody] of Object.entries(handlers)) {
    39→+      if (url.includes(pattern)) {
    40→+        return new Response(JSON.stringify(responseBody), {
    41→+          status: 200,
    42→+          headers: { 'Content-Type': 'application/json' },
    43→+        });
    44→+      }
    45→+    }
    46→+    return originalFetchRef.current(input, init);
    47→+  };
    48→+
    49→+  useEffect(() => {
    50→+    return () => {
    51→+      window.fetch = originalFetchRef.current;
    52→+    };
    53→+  }, []);
    54→+
    55→+  return <Story />;
    56→+};
    57→+
    58→+export const withFetchMock: Decorator = (Story, { parameters }) => {
    59→+  const handlers = parameters.fetchMock as Record<string, unknown> | undefined;
    60→+  if (!handlers) return <Story />;
    61→+  return <FetchMockWrapper Story={Story} handlers={handlers} />;
    62→+};
