+import type { Meta, StoryObj } from '@storybook/react';
+import { Carousel } from '@customink/pigment-extensions/reco/ProductsCarouselWidget/Atoms/Carousel';
+import type { CarouselProps } from '@customink/pigment-extensions/reco/ProductsCarouselWidget/Atoms/Carousel';
+
+const meta: Meta<CarouselProps> = {
+  title: 'Extensions/Reco/Atoms/Carousel',
+  component: Carousel,
+  parameters: {
+    layout: 'padded',
+    docs: {
+      description: {
+        component:
+          'Internal atom for ProductsCarouselWidget. Thin keen-slider wrapper with arrow navigation and resize handling. NOT exported from the reco public API.',
+      },
+    },
+  },
+  argTypes: {
+    slidesPerView: { control: { type: 'number', min: 1, max: 8, step: 0.25 } },
+    spacing: { control: { type: 'number', min: 0, max: 32, step: 4 } },
+    loop: { control: 'boolean' },
+    arrows: { control: 'boolean' },
+  },
+};
+
+export default meta;
+type Story = StoryObj<CarouselProps>;
+
+const SLIDE_COLORS = ['#e8f4fd', '#fef9e7', '#e8f8f5', '#fdf2f8', '#fef5e7', '#f4ecf7', '#eafaf1', '#fdfefe'];
+
+const slides = SLIDE_COLORS.map((color, i) => (
+  <div
+    key={i}
+    style={{
+      height: 200,
+      background: color,
+      border: '1px solid #e0e0e0',
+      borderRadius: '0.5rem',
+      display: 'flex',
+      alignItems: 'center',
+      justifyContent: 'center',
+      fontSize: '1.5rem',
+      fontWeight: 700,
+      color: '#555',
+    }}
+  >
+    {i + 1}
+  </div>
+));
+
+export const Default: Story = {
+  args: { slidesPerView: 5, spacing: 16, loop: true, arrows: true },
+  render: (args) => <Carousel {...args}>{slides}</Carousel>,
+};
+
+export const NoArrows: Story = {
+  name: 'No Arrows',
+  args: { slidesPerView: 5, spacing: 16, loop: true, arrows: false },
+  render: (args) => <Carousel {...args}>{slides}</Carousel>,
+};
+
+export const NoLoop: Story = {
+  name: 'No Loop',
+  parameters: {
+    docs: {
+      description: { story: 'Loop is disabled when the number of products does not exceed perView.' },
+    },
+  },
+  args: { slidesPerView: 5, spacing: 16, loop: false, arrows: false },
+  render: (args) => <Carousel {...args}>{slides.slice(0, 3)}</Carousel>,
+};
+
+export const Mobile: Story = {
+  name: 'Mobile (2.25 perView)',
+  parameters: {
+    docs: {
+      description: { story: 'Mobile breakpoint — 2.25 slides visible, peek of next card.' },
+    },
+  },
+  args: { slidesPerView: 2.25, spacing: 8, loop: true, arrows: false },
+  render: (args) => <Carousel {...args}>{slides}</Carousel>,
+};
+
+export const API: Story = {
+  args: { slidesPerView: 5, spacing: 16, loop: true, arrows: true },
+  render: (args) => <Carousel {...args}>{slides}</Carousel>,
+};
