+  },
+  args: {
+    placement: 'auto',
+  },
+};
+
+export default meta;
+type Story = StoryObj<PopoverProps>;
+
+const TriggerButton = ({ label }: { label: string }) => (
+  <button
+    type="button"
+    style={{
+      padding: '0.25rem 0.5rem',
+      border: 'none',
+      background: 'none',
+      cursor: 'pointer',
+      fontSize: '0.875rem',
+      fontWeight: 700,
+      color: 'var(--neutral-text-primary)',
+      textDecoration: 'underline',
+      textDecorationStyle: 'dashed',
+      textUnderlineOffset: '3px',
+    }}
