+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const PlacementTop: Story = {
+  name: 'Placement: Top',
+  render: (args) => (
+    <Popover {...args} placement="top" content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const PlacementRight: Story = {
+  name: 'Placement: Right',
+  render: (args) => (
+    <Popover {...args} placement="right" content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const PlacementLeft: Story = {
+  name: 'Placement: Left',
+  render: (args) => (
+    <Popover {...args} placement="left" content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
+
+export const AutoPlacement: Story = {
+  name: 'Auto Placement',
+  parameters: {
+    layout: 'fullscreen',
+    docs: {
+      description: {
+        story:
+          "placement='auto' measures available viewport space when the popover opens and picks the side with more room. Hover the top trigger — it opens downward. Hover the bottom trigger — it opens upward.",
+      },
+    },
+  },
+  render: (args) => (
+    <div
+      style={{
+        height: '100dvh',
+        display: 'flex',
+        flexDirection: 'column',
+        justifyContent: 'space-between',
+        padding: '1rem',
+      }}
+    >
+      <Popover {...args} placement="auto" content={PRICE_DETAILS_CONTENT}>
+        <TriggerButton label="Near top → opens below" />
+      </Popover>
+      <Popover {...args} placement="auto" content={PRICE_DETAILS_CONTENT}>
+        <TriggerButton label="Near bottom → opens above" />
+      </Popover>
+    </div>
+  ),
+};
+
+export const API: Story = {
+  render: (args) => (
+    <Popover {...args} content={PRICE_DETAILS_CONTENT}>
+      <TriggerButton label="Pricing Details" />
+    </Popover>
+  ),
+};
