+
+describe('FavoriteButton', () => {
+  it('renders "Add to favorites" label when not favorited', () => {
+    render(<FavoriteButton isFavorited={false} onClick={() => {}} />);
+    expect(screen.getByRole('button', { name: 'Add to favorites' })).toBeInTheDocument();
+  });
+
+  it('renders "Remove from favorites" label when favorited', () => {
+    render(<FavoriteButton isFavorited={true} onClick={() => {}} />);
+    expect(screen.getByRole('button', { name: 'Remove from favorites' })).toBeInTheDocument();
+  });
+
+  it('sets aria-pressed to false when not favorited', () => {
+    render(<FavoriteButton isFavorited={false} onClick={() => {}} />);
+    expect(screen.getByRole('button')).toHaveAttribute('aria-pressed', 'false');
+  });
+
+  it('sets aria-pressed to true when favorited', () => {
+    render(<FavoriteButton isFavorited={true} onClick={() => {}} />);
+    expect(screen.getByRole('button')).toHaveAttribute('aria-pressed', 'true');
+  });
+
+  it('calls onClick when clicked', () => {
+    const onClick = jest.fn();
+    render(<FavoriteButton isFavorited={false} onClick={onClick} />);
+    fireEvent.click(screen.getByRole('button'));
+    expect(onClick).toHaveBeenCalledTimes(1);
+  });
+
+  it('forwards ref to the button element', () => {
