+  onClick: React.MouseEventHandler<HTMLButtonElement>;
+  className?: string;
+  style?: React.CSSProperties;
+};
+
+/** Heart toggle for the `imageOverlay` slot of RecommendationsProductCard. Consuming app owns favorites state. */
+export const FavoriteButton = React.forwardRef<HTMLButtonElement, FavoriteButtonProps>(function FavoriteButton(
