  2420→+
  2421→+// Off-screen sentinel: keeps the panel in the DOM for fade-out but outside the viewport.
  2422→+const OFFSCREEN: React.CSSProperties = { position: 'fixed', top: -9999, left: -9999 };
  2423→+
  2424→+function clamp(value: number, min: number, max: number): number {
