  2428→+/** Returns a viewport-clamped `position:fixed` style. Reads offsetWidth/offsetHeight while the panel is off-screen for single-pass positioning. */
  2429→+function computeClampedStyle(triggerRect: DOMRect, side: Side, panelW: number, panelH: number): React.CSSProperties {
  2430→+  const vw = window.innerWidth;
  2431→+  const vh = window.innerHeight;
