  2433→+  switch (side) {
  2434→+    case 'bottom': {
  2435→+      const left = clamp(triggerRect.left + triggerRect.width / 2, VP_PAD + panelW / 2, vw - VP_PAD - panelW / 2);
  2436→+      const top = clamp(triggerRect.bottom + GAP_PX, VP_PAD, vh - VP_PAD - panelH);
  2437→+      return { position: 'fixed', top, left };
  2438→+    }
  2439→+    case 'top': {
  2440→+      const left = clamp(triggerRect.left + triggerRect.width / 2, VP_PAD + panelW / 2, vw - VP_PAD - panelW / 2);
  2441→+      const top = clamp(triggerRect.top - GAP_PX - panelH, VP_PAD, vh - VP_PAD - panelH);
  2442→+      return { position: 'fixed', top, left };
  2443→+    }
  2444→+    case 'right': {
  2445→+      const left = clamp(triggerRect.right + GAP_PX, VP_PAD, vw - VP_PAD - panelW);
  2446→+      const top = clamp(triggerRect.top + triggerRect.height / 2, VP_PAD + panelH / 2, vh - VP_PAD - panelH / 2);
  2447→+      return { position: 'fixed', left, top };
  2448→+    }
  2449→+    case 'left': {
  2450→+      const left = clamp(triggerRect.left - GAP_PX - panelW, VP_PAD, vw - VP_PAD - panelW);
  2451→+      const top = clamp(triggerRect.top + triggerRect.height / 2, VP_PAD + panelH / 2, vh - VP_PAD - panelH / 2);
