+  spacing?: number;
+  loop?: boolean;
+  arrows?: boolean;
+  className?: string;
+  style?: React.CSSProperties;
+};
+
+/** Thin keen-slider wrapper. NOT exported from the reco public API. */
+export const Carousel = React.forwardRef<HTMLDivElement, CarouselProps>(function Carousel(
+  { children, slidesPerView = 1, spacing = 0, loop = true, arrows = true, className, style },
+  ref,
+) {
+  const [keenRef, instanceRef] = useKeenSlider<HTMLDivElement>({
+    loop,
+    mode: 'snap',
+    slides: { perView: slidesPerView, spacing },
+  });
+
+  // useResizeObserver needs a RefObject; keenRef is a callback ref with no .current
+  const boundingBoxRef = useRef<HTMLDivElement>(null);
+  const mergedRef = useCallback(
+    (node: HTMLDivElement | null) => {
+      (boundingBoxRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
+      keenRef(node);
+    },
+    [keenRef],
+  );
+
+  useResizeObserver(boundingBoxRef, () => instanceRef.current?.update());
+
+  useEffect(() => {
+    instanceRef.current?.update({ loop, mode: 'snap', slides: { perView: slidesPerView, spacing } });
+  }, [slidesPerView, spacing, loop]);
+
+  const handlePrev = useCallback((e: React.MouseEvent) => {
+    e.stopPropagation();
+    instanceRef.current?.prev();
+  }, []);
+
+  const handleNext = useCallback((e: React.MouseEvent) => {
+    e.stopPropagation();
+    instanceRef.current?.next();
+  }, []);
+
+  const rootClass = [styles.root, className].filter(Boolean).join(' ');
+
+  const arrowPath =
+    'M8.29289 5.70711C7.90237 5.31658 7.90237 4.68342 8.29289 4.29289C8.68342 3.90237 9.31658 3.90237 9.70711 4.29289L16.7071 11.2929C17.0976 11.6834 17.0976 12.3166 16.7071 12.7071L9.70711 19.7071C9.31658 20.0976 8.68342 20.0976 8.29289 19.7071C7.90237 19.3166 7.90237 18.6834 8.29289 18.2929L14.5858 12L8.29289 5.70711Z';
+
+  return (
+    <div ref={ref} className={rootClass} style={style}>
+      {arrows ? (
+        <div className={styles.arrowContainer}>
+          <button type="button" className={`${styles.arrow} ${styles.arrowPrev}`} onClick={handlePrev} aria-label="Previous">
+            <svg width={20} height={20} viewBox="0 0 24 24" fill="none" aria-hidden="true">
+              <path fillRule="evenodd" clipRule="evenodd" d={arrowPath} fill="currentColor" />
+            </svg>
+          </button>
+          <button type="button" className={`${styles.arrow} ${styles.arrowNext}`} onClick={handleNext} aria-label="Next">
+            <svg width={20} height={20} viewBox="0 0 24 24" fill="none" aria-hidden="true">
+              <path fillRule="evenodd" clipRule="evenodd" d={arrowPath} fill="currentColor" />
+            </svg>
+          </button>
+        </div>
+      ) : null}
+
+      <div ref={mergedRef} className="keen-slider">
+        {React.Children.map(children, (child, i) => (
+          <div key={React.isValidElement(child) ? child.key ?? i : i} className="keen-slider__slide">
+            {child}
+          </div>
+        ))}
+      </div>
+    </div>
+  );
+});
+
+Carousel.displayName = 'Carousel';
