+import { render, screen } from '@testing-library/react';
+import { createRef } from 'react';
+import { LoadingSkeleton } from './LoadingSkeleton';
+
+describe('LoadingSkeleton', () => {
+  it('renders the skeleton container', () => {
+    render(<LoadingSkeleton />);
+    expect(screen.getByTestId('carousel-skeleton')).toBeInTheDocument();
+  });
+
+  it('renders 4 card placeholders by default', () => {
+    const { container } = render(<LoadingSkeleton />);
+    const cardsGrid = container.querySelector('[data-testid="carousel-skeleton"] > div:last-child');
+    expect(cardsGrid?.children).toHaveLength(4);
+  });
+
+  it('renders the specified number of card placeholders', () => {
+    const { container } = render(<LoadingSkeleton count={6} />);
+    const cardsGrid = container.querySelector('[data-testid="carousel-skeleton"] > div:last-child');
+    expect(cardsGrid?.children).toHaveLength(6);
+  });
+
+  it('forwards ref to the root element', () => {
+    const ref = createRef<HTMLDivElement>();
+    render(<LoadingSkeleton ref={ref} />);
+    expect(ref.current).toBe(screen.getByTestId('carousel-skeleton'));
+  });
+
+  it('applies custom className', () => {
+    render(<LoadingSkeleton className="custom" />);
+    expect(screen.getByTestId('carousel-skeleton').className).toContain('custom');
+  });
+});
