+import React from 'react';
+import styles from './LoadingSkeleton.module.css';
+
+export type LoadingSkeletonProps = {
+  /** Number of card placeholders to render. Should match the current breakpoint's perView. */
+  count?: number;
+  /** Gap between cards in pixels. Should match the current breakpoint's spacing. */
+  gap?: number;
+  className?: string;
+  style?: React.CSSProperties;
+};
+
+/** Shimmer placeholder for the carousel. Ported from CarouselSkeleton in catalog's TrendingProducts feature. */
+export const LoadingSkeleton = React.forwardRef<HTMLDivElement, LoadingSkeletonProps>(function LoadingSkeleton(
+  { count = 4, gap = 8, className, style },
+  ref,
+) {
+  const rootClass = [styles.root, className].filter(Boolean).join(' ');
+
+  return (
+    <div ref={ref} className={rootClass} style={style} data-testid="carousel-skeleton">
+      <div className={`${styles.shimmer} ${styles.header}`} />
+      <div className={styles.cards} style={{ gridTemplateColumns: `repeat(${count}, 1fr)`, gap: `${gap}px` }}>
+        {Array.from({ length: count }, (_, i) => (
+          <div key={i} className={`${styles.shimmer} ${styles.card}`}>
+            <div className={styles.cardContent}>
+              <div className={`${styles.shimmer} ${styles.cardTitle}`} />
+              <div className={`${styles.shimmer} ${styles.cardPrice}`} />
+            </div>
+          </div>
+        ))}
+      </div>
+    </div>
+  );
+});
+
+LoadingSkeleton.displayName = 'LoadingSkeleton';
