+import React from 'react';
+import { Typography } from '@customink/pigment-react';
+import styles from './ProductCardPriceDetailsContent.module.css';
+
+export type ProductCardPriceDetailsContentProps = {
+  isLoading: boolean;
+  isError: boolean;
+  /** Map of quantity → formatted price string (e.g. "27.44"), null when price unavailable. */
+  priceDetailsData: Record<number, string | null> | null;
+  /** Sorted list of quantities shown in the table. */
+  quotableQuantities: number[];
+  /** Number of front print colors — used for the design description title. @default 1 */
+  frontColor?: number;
+  /** Number of back print colors — used for the design description title. @default 0 */
+  backColor?: number;
+  /** Show the "Save" column with percentage savings relative to the first tier. @default false */
+  showSavings?: boolean;
+};
+
+/** Pure presentational price-details panel. Use `ProductCardPriceDetailsConnected` for the data-fetching version. */
+export function ProductCardPriceDetailsContent({
+  isLoading,
+  isError,
+  priceDetailsData,
+  quotableQuantities,
+  frontColor = 1,
+  backColor = 0,
+  showSavings = false,
+}: ProductCardPriceDetailsContentProps) {
+  const colorCount = Math.max(frontColor, backColor);
+  const sideCount = backColor > 0 ? 2 : 1;
+
+  const basePrice = priceDetailsData ? Number(priceDetailsData[quotableQuantities[0]]) : null;
+
+  if (isError) {
+    return (
+      <div className={styles.root}>
+        <Typography variant="uiTextSmall">Unable to load pricing. Please try again.</Typography>
+      </div>
+    );
+  }
+
+  return (
+    <div className={styles.root}>
+      <Typography variant="uiTextSmall" className={styles.title}>
+        For a {colorCount}-color, {sideCount}-sided design:
+      </Typography>
+
+      <table className={styles.table}>
+        <thead>
+          <tr className={styles.headerRow}>
+            <th className={styles.colQty}>
+              <Typography variant="uiTextSmall" fontWeight="bold" component="span">
+                Quantity
+              </Typography>
+            </th>
+            {showSavings ? (
+              <th className={styles.colSave}>
+                <Typography variant="uiTextSmall" fontWeight="bold" component="span">
+                  Save
+                </Typography>
+              </th>
+            ) : null}
+            <th>
+              <Typography variant="uiTextSmall" fontWeight="bold" component="span">
+                Price/Item
+              </Typography>
+            </th>
+          </tr>
+        </thead>
+        <tbody>
+          {quotableQuantities.map((qty, index) => {
+            const priceStr = priceDetailsData?.[qty];
+            const price = priceStr != null ? Number(priceStr) : null;
+            const savePercent =
+              index > 0 && basePrice != null && price != null && basePrice > 0
+                ? Math.round((1 - price / basePrice) * 100)
+                : null;
+
+            return (
+              <tr key={qty} className={styles.row}>
+                <td>
+                  <Typography variant="uiTextSmall" component="span">
+                    {qty}
+                  </Typography>
+                  {index === 0 ? (
+                    <Typography variant="uiTextTiny" component="span" className={styles.minLabel}>
+                      (minimum)
+                    </Typography>
+                  ) : null}
+                </td>
+                {showSavings ? (
+                  <td>
+                    {savePercent != null && savePercent > 0 ? (
+                      <Typography variant="uiTextTiny" fontWeight="bold" component="span" className={styles.saveBadge}>
+                        {savePercent}%
+                      </Typography>
+                    ) : null}
+                  </td>
+                ) : null}
+                <td>
+                  {isLoading ? (
+                    <span className={styles.priceShimmer} aria-hidden="true" />
+                  ) : priceStr != null ? (
+                    <Typography variant="uiTextSmall" component="span">
+                      ${Number(priceStr).toFixed(2)}
+                    </Typography>
+                  ) : (
+                    <Typography variant="uiTextSmall" component="span">
+                      —
+                    </Typography>
+                  )}
+                </td>
+              </tr>
+            );
+          })}
+        </tbody>
+      </table>
+
+      <div className={styles.footer}>
+        <Typography variant="uiTextSmall">All-inclusive pricing includes</Typography>
+        <ul className={styles.footerList}>
+          {['delivery', 'artwork review', 'artwork setup'].map((item) => (
+            <li key={item}>
+              <Typography variant="uiTextSmall" component="span">
+                <strong>FREE</strong> {item}
+              </Typography>
+            </li>
+          ))}
+        </ul>
+      </div>
+    </div>
+  );
+}
+
+ProductCardPriceDetailsContent.displayName = 'ProductCardPriceDetailsContent';
