+import React, { useCallback } from 'react';
+import { Typography } from '@customink/pigment-react';
+import type { UnitPrice } from '../../types';
+import styles from './RecommendationsProductCard.module.css';
+import { formatRatingScore, formatRatingCount, formatPrice } from '../../utils';
+
+// SVG path from v0 StarFilledIcon (not on public API)
+const STAR_FILLED_PATH =
+  'M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.783-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z';
+
+export type RecommendationsProductCardProps = {
+  styleId: number;
+  name: string;
+  linkHref: string;
+  imageSrc: string;
+  imageSrcSet?: string;
+  /** @default name */
+  imageAlt?: string;
+  minQty: number;
+  ratingScore?: number;
+  ratingCount?: number;
+  defaultUnitPrices: UnitPrice[];
+  defaultQuoteQty: number;
+  onClick?: (styleId: number, e: React.MouseEvent) => void;
+  /** Slot rendered as an absolute overlay on the product image (e.g. FavoriteButton) */
+  imageOverlay?: React.ReactNode;
+  /**
+   * Render prop for custom price display (e.g. ProductCardPriceDetailsConnected).
+   * Replaces the default price derived from defaultUnitPrices.
+   */
+  renderPriceDetails?: () => React.ReactNode;
+  children?: React.ReactNode;
+  className?: string;
+  style?: React.CSSProperties;
+};
+
+/** Internal product card molecule. Not on the public API. */
+export const RecommendationsProductCard = React.forwardRef<HTMLDivElement, RecommendationsProductCardProps>(
+  function RecommendationsProductCard(
+    {
+      styleId,
+      name,
+      linkHref,
+      imageSrc,
+      imageSrcSet,
+      imageAlt,
+      minQty,
+      ratingScore,
+      ratingCount,
+      defaultUnitPrices,
+      defaultQuoteQty,
+      onClick,
+      imageOverlay,
+      renderPriceDetails,
+      children,
+      className,
+      style,
+    },
+    ref,
+  ) {
+    const hasRating = ratingScore != null && ratingScore > 0 && ratingCount != null && ratingCount > 0;
+    const formattedPrice = formatPrice(defaultUnitPrices, defaultQuoteQty);
+    const cardClass = [styles.card, className].filter(Boolean).join(' ');
+
+    const handleClick = useCallback(
+      (e: React.MouseEvent) => {
+        onClick?.(styleId, e);
+      },
+      [onClick, styleId],
+    );
+
+    const handleKeyDown = useCallback(
+      (e: React.KeyboardEvent) => {
+        if (e.key === 'Enter' || e.key === ' ') {
+          onClick?.(styleId, e as unknown as React.MouseEvent);
+        }
+      },
+      [onClick, styleId],
+    );
+
+    return (
+      <div
+        ref={ref}
+        className={cardClass}
+        style={style}
+        role="button"
+        tabIndex={0}
+        onClick={handleClick}
+        onKeyDown={handleKeyDown}
+      >
+        {/* overlay is a sibling to <a> — avoids button-inside-anchor */}
+        <div className={styles.imageContainer}>
+          <a href={linkHref} className={styles.imageLink} tabIndex={-1} aria-hidden="true">
+            <div className={styles.imageWrapper}>
+              <div className={styles.imageShadow} aria-hidden="true" />
+              <img src={imageSrc} srcSet={imageSrcSet} alt={imageAlt ?? name} className={styles.image} />
+            </div>
+          </a>
+          {imageOverlay}
+        </div>
+
+        <div className={styles.content}>
+          <a href={linkHref} className={styles.nameLink}>
+            <Typography variant="uiTextSmall" fontWeight="bold" className={styles.name} title={name}>
+              {name}
+            </Typography>
+          </a>
+
+          {hasRating ? (
+            <div className={styles.ratingRow}>
+              <svg
+                width={20}
+                height={20}
+                viewBox="0 0 24 24"
+                fill="none"
+                xmlns="http://www.w3.org/2000/svg"
+                aria-hidden="true"
+                className={styles.starIcon}
+              >
+                <path fillRule="evenodd" clipRule="evenodd" d={STAR_FILLED_PATH} fill="currentColor" />
+              </svg>
+              <Typography variant="uiTextSmall" className={styles.ratingScore}>
+                {formatRatingScore(ratingScore)}
+              </Typography>
+              <span className={styles.ratingCount}>{formatRatingCount(ratingCount)}</span>
+            </div>
+          ) : null}
+
+          <div className={styles.priceArea}>
+            {renderPriceDetails ? (
+              renderPriceDetails()
+            ) : (
+              <>
+                {formattedPrice !== null && (
+                  <Typography variant="uiTextTiny" className={styles.price}>
+                    {formattedPrice.originalAmount != null ? (
+                      <>
+                        <span className={styles.originalPrice}>{formattedPrice.originalAmount}</span>
+                        <span className={styles.discountPrice}>{formattedPrice.amount}</span>
+                      </>
+                    ) : (
+                      <span className={styles.priceAmount}>{formattedPrice.amount}</span>
+                    )}
+                    {formattedPrice.suffix}
+                  </Typography>
+                )}
+              </>
+            )}
+          </div>
+
+          <Typography variant="uiTextTiny" className={styles.minQty}>
+            {minQty === 1 ? 'No Minimum' : `Minimum ${minQty}`}
+          </Typography>
+
+          {children}
+        </div>
+      </div>
+    );
+  },
+);
+
+RecommendationsProductCard.displayName = 'RecommendationsProductCard';
