  3854→+import { useEffect, useState } from 'react';
  3855→+import units from '@customink/design-tokens/semantics/units';
  3856→+import type { Breakpoint, UnitPrice } from './types';
  3857→+
  3858→+const BREAKPOINTS = {
  3859→+  mobile: parseInt(units.size.breakpoint.tablet, 10),
  3860→+  desktop: parseInt(units.size.breakpoint.desktop, 10),
  3861→+};
  3862→+
  3863→+function getBreakpoint(width: number): Breakpoint {
  3864→+  if (width < BREAKPOINTS.mobile) return 'mobile';
  3865→+  if (width < BREAKPOINTS.desktop) return 'tablet';
  3866→+  return 'desktop';
  3867→+}
  3868→+
  3869→+export const DEFAULT_SLIDES_CONFIG: Record<Breakpoint, { perView: number; spacing: number }> = {
  3870→+  mobile: { perView: 2.25, spacing: 8 },
  3871→+  tablet: { perView: 4, spacing: 16 },
  3872→+  desktop: { perView: 5, spacing: 16 },
  3873→+};
  3874→+
  3875→+export function getSlidesConfig(
  3876→+  breakpoint: Breakpoint,
  3877→+  overrides?: Partial<Record<Breakpoint, { perView: number; spacing: number }>>,
  3878→+): { perView: number; spacing: number } {
  3879→+  return { ...DEFAULT_SLIDES_CONFIG[breakpoint], ...overrides?.[breakpoint] };
  3880→+}
  3881→+
  3882→+export function useBreakpoint(): Breakpoint {
  3883→+  const [breakpoint, setBreakpoint] = useState<Breakpoint>(() =>
  3884→+    typeof window !== 'undefined' ? getBreakpoint(window.innerWidth) : 'desktop',
  3885→+  );
  3886→+
  3887→+  useEffect(() => {
  3888→+    const mqMobile = window.matchMedia(`(max-width: ${BREAKPOINTS.mobile - 1}px)`);
  3889→+    const mqTablet = window.matchMedia(`(min-width: ${BREAKPOINTS.mobile}px) and (max-width: ${BREAKPOINTS.desktop - 1}px)`);
  3890→+    const handler = () => setBreakpoint(getBreakpoint(window.innerWidth));
  3891→+    mqMobile.addEventListener('change', handler);
  3892→+    mqTablet.addEventListener('change', handler);
  3893→+    return () => {
  3894→+      mqMobile.removeEventListener('change', handler);
  3895→+      mqTablet.removeEventListener('change', handler);
  3896→+    };
  3897→+  }, []);
  3898→+
  3899→+  return breakpoint;
  3900→+}
  3901→+
  3902→+export function formatRatingScore(score: number): string {
  3903→+  const adjusted = score < 1 ? 1 : score;
  3904→+  return adjusted.toFixed(1);
  3905→+}
  3906→+
  3907→+export function formatRatingCount(count: number): string | null {
  3908→+  if (Number.isNaN(count)) return null;
  3909→+  const cap = 10_000;
  3910→+  const capped = count > cap ? cap : count;
  3911→+  const formatted = capped.toLocaleString();
  3912→+  return `(${count > cap ? `${formatted}+` : formatted})`;
  3913→+}
  3914→+
  3915→+export function formatPrice(
  3916→+  unitPrices: UnitPrice[],
  3917→+  quoteQty: number,
  3918→+): { amount: string; suffix: string; originalAmount?: string } | null {
  3919→+  if (!unitPrices.length) return null;
  3920→+  const match = unitPrices.find((p) => p.quantity === quoteQty) ?? unitPrices[0];
  3921→+  const isDiscounted = match.regularPrice != null && match.regularPrice > match.price;
  3922→+  return {
  3923→+    amount: `$${match.price.toFixed(2)}`,
  3924→+    suffix: `/ea for ${match.quantity} items`,
  3925→+    ...(isDiscounted && match.regularPrice != null && { originalAmount: `$${match.regularPrice.toFixed(2)}` }),
  3926→+  };
  3927→+}
