+import React, { useEffect, useRef } from 'react';
+import { Typography } from '@customink/pigment-react';
+import type { ProductsCarouselWidgetProps } from './types';
+import { Carousel } from './Atoms/Carousel';
+import { LoadingSkeleton } from './Atoms/LoadingSkeleton';
+import { RecommendationsProductCard } from './Molecules/RecommendationsProductCard';
+import { useBreakpoint, getSlidesConfig } from './utils';
+import styles from './ProductsCarouselWidget.module.css';
+
+/**
+ * Data fetching stays in the consuming app. Inject FavoriteButton via `renderFavoriteButton`
+ * and wrap with FavoritesProvider in the consuming app.
+ */
+export const ProductsCarouselWidget = React.forwardRef<HTMLDivElement, ProductsCarouselWidgetProps>(
+  function ProductsCarouselWidget(
+    {
+      products,
+      isLoading = false,
+      title = 'Trending Products',
+      onWidgetViewed,
+      onCardClicked,
+      renderFavoriteButton,
+      renderPriceDetails,
+      slidesConfig,
+      children,
+      className,
+      style,
+    },
+    ref,
+  ) {
+    const breakpoint = useBreakpoint();
+    const { perView, spacing } = getSlidesConfig(breakpoint, slidesConfig);
+    const loop = products.length > perView;
+    const showArrows = loop && breakpoint !== 'mobile';
+
+    const widgetRef = useRef<HTMLDivElement>(null);
+    const hasFiredViewEvent = useRef(false);
+
+    useEffect(() => {
+      const el = widgetRef.current;
+      if (!el || products.length === 0 || hasFiredViewEvent.current) return;
+
+      const observer = new IntersectionObserver(
+        (entries) => {
+          entries.forEach((entry) => {
+            if (entry.isIntersecting && !hasFiredViewEvent.current) {
+              onWidgetViewed?.(products);
+              hasFiredViewEvent.current = true;
+            }
+          });
+        },
+        { threshold: 0.1 },
+      );
+
+      observer.observe(el);
+      return () => observer.disconnect();
+    }, [products, onWidgetViewed]);
+
+    if (isLoading) return <LoadingSkeleton count={Math.floor(perView)} gap={spacing} />;
+    if (products.length === 0) return null;
+
+    const rootClass = [styles.root, className].filter(Boolean).join(' ');
+
+    return (
+      <div ref={ref} className={rootClass} style={style}>
+        <div ref={widgetRef}>
+          <Typography variant="heading3" className={styles.title}>
+            {title}
+          </Typography>
+
+          <Carousel slidesPerView={perView} spacing={spacing} loop={loop} arrows={showArrows}>
+            {products.map((product, index) => (
+              <RecommendationsProductCard
+                key={product.styleId}
+                styleId={product.styleId}
+                name={product.name}
+                linkHref={product.link}
+                imageSrc={product.imageSrc}
+                imageSrcSet={product.imageSrcSet}
+                imageAlt={product.imageAlt}
+                minQty={product.minQty}
+                ratingScore={product.ratingScore}
+                ratingCount={product.ratingCount}
+                defaultUnitPrices={product.defaultUnitPrices}
+                defaultQuoteQty={product.defaultQuoteQty}
+                // eslint-disable-next-line react/jsx-no-bind
+                onClick={() => onCardClicked?.(product, index)}
+                imageOverlay={renderFavoriteButton?.(product)}
+                // eslint-disable-next-line react/jsx-no-bind
+                renderPriceDetails={renderPriceDetails ? () => renderPriceDetails(product) : undefined}
+              />
+            ))}
+          </Carousel>
+
+          {children}
+        </div>
+      </div>
+    );
+  },
+);
+
+ProductsCarouselWidget.displayName = 'ProductsCarouselWidget';
