+import React from 'react';
+import { useTrendingProductsByCategory } from '../useTrendingProductsByCategory';
+import type { UseTrendingProductsByCategoryOptions } from '../useTrendingProductsByCategory';
+import { ProductsCarouselWidget } from '../ProductsCarouselWidget';
+import type { ProductsCarouselWidgetProps } from '../ProductsCarouselWidget/types';
+
+export type TrendingProductsCarouselProps = UseTrendingProductsByCategoryOptions &
+  Omit<ProductsCarouselWidgetProps, 'products' | 'isLoading'> & {
+    /** Called when the recommendations fetch fails. Use for logging or showing a toast. */
+    onError?: () => void;
+  };
+
+/**
+ * Zero-config carousel for trending products.
+ * Fetches data from the recommendations service and renders ProductsCarouselWidget.
+ *
+ * Minimal usage:
+ * ```tsx
+ * <TrendingProductsCarousel categoryId={574} />
+ * ```
+ */
+export const TrendingProductsCarousel = React.forwardRef<HTMLDivElement, TrendingProductsCarouselProps>(
+  function TrendingProductsCarousel(
+    { categoryId, limit, excludeProductIds, baseUrl, enabled, imageDesignCid, onError, ...widgetProps },
+    ref,
+  ) {
+    const { products, isLoading, isError } = useTrendingProductsByCategory({
+      categoryId,
+      limit,
+      excludeProductIds,
+      baseUrl,
+      enabled,
+      imageDesignCid,
+    });
+
+    React.useEffect(() => {
+      if (isError) onError?.();
+    }, [isError, onError]);
+
+    return <ProductsCarouselWidget ref={ref} products={products} isLoading={isLoading} {...widgetProps} />;
+  },
+);
+
+TrendingProductsCarousel.displayName = 'TrendingProductsCarousel';
