+import { Suspense } from "react";
+import {
+  getRelatedStyles,
+  getRecommendedStyles,
+  getRecoBrands,
+} from "@/lib/related-products/server";
+import type { RelatedProductsInitialData } from "@/lib/related-products/client";
+import Loader from "./tabbed-view/loader";
+import RelatedProductsClient from "./related-products-client";
+
+interface RelatedProductsServerProps {
+  styleId: string;
+  colorId: string;
+  brand?: string;
+}
+
+async function RelatedProductsContent({
+  styleId,
+  colorId,
+  brand,
+}: RelatedProductsServerProps): Promise<React.JSX.Element> {
+  const [relatedStyles, recommendations, recoBrands] = await Promise.all([
+    getRelatedStyles(styleId, colorId),
+    getRecommendedStyles(styleId, colorId, 30),
+    brand ? getRecoBrands(styleId, colorId, brand, 30) : null,
+  ]);
+
+  const initialData: RelatedProductsInitialData = {
+    relatedStyles,
+    recommendations,
+    recoBrands,
+  };
+
+  return <RelatedProductsClient initialData={initialData} />;
+}
+
+export default function RelatedProductsServer(
+  props: RelatedProductsServerProps,
+): React.JSX.Element {
+  return (
+    <Suspense fallback={<Loader />}>
+      <RelatedProductsContent {...props} />
+    </Suspense>
+  );
+}
